+  private getCursorPagination(opts: CrudOptionsType<T>) {
+    const cursorProvided = opts.cursor !== undefined;
+    const hasOrderBy = opts.orderBy !== undefined;
+    if (cursorProvided && !hasOrderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (cursorProvided && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!hasOrderBy || !opts.limit) {
+      delete opts.cursor;
+      return undefined;
+    }
+
+    const sort = this.normalizeCursorSort(opts.orderBy);
+    const cursor = cursorProvided
+      ? this.decodeCursor(opts.cursor, sort)
+      : undefined;
+    delete opts.cursor;
+    return {
+      limit: opts.limit,
+      sort,
+      orderBy: sort.map(({ field, direction }) => ({ [field]: direction })),
+      filter: cursor ? this.makeCursorFilter(cursor, sort) : undefined,
+    };
+  }
+
+  private normalizeCursorSort(orderBy: CrudOptionsType<T>['orderBy']) {
+    const sort: { field: string; direction: 'asc' | 'desc' }[] = [];
+    for (const order of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      if (!order || typeof order !== 'object' || Array.isArray(order)) {
+        throw new BadRequestException('orderBy must contain sort fields');
+      }
+      for (const [field, value] of Object.entries(order)) {
+        const direction = this.normalizeCursorDirection(value);
+        if (!direction) {
+          throw new BadRequestException('orderBy direction must be asc or desc');
+        }
+        sort.push({ field, direction });
+      }
+    }
+    const idField = this.crudConfig.id_field;
+    if (!sort.some(({ field }) => field === idField)) {
+      sort.push({ field: idField, direction: 'asc' });
+    }
+    return sort;
+  }
+
+  private normalizeCursorDirection(value: unknown): 'asc' | 'desc' | undefined {
+    if (value === 1) return 'asc';
+    if (value === -1) return 'desc';
+    const direction = String(value).toLowerCase();
+    if (direction.startsWith('asc')) return 'asc';
+    if (direction.startsWith('desc')) return 'desc';
+    return undefined;
+  }
+
+  private decodeCursor(
+    encoded: string,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ): Record<string, any> {
+    let cursor: unknown;
+    try {
+      if (
+        typeof encoded !== 'string' ||
+        !/^[A-Za-z0-9+/]*={0,2}$/.test(encoded) ||
+        encoded.length % 4 === 1
+      ) {
+        throw new Error('invalid base64');
+      }
+      cursor = JSON.parse(Buffer.from(encoded, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!cursor || typeof cursor !== 'object' || Array.isArray(cursor)) {
+      throw new BadRequestException('cursor must be a JSON object');
+    }
+
+    const payload = cursor as Record<string, any>;
+    const expectedSort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const { field } of sort) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    return payload;
+  }
+
+  private makeCursorFilter(
+    cursor: Record<string, any>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    return {
+      $or: sort.map(({ field, direction }, index) => ({
+        $and: [
+          ...sort.slice(0, index).map((previous) => ({
+            [previous.field]: cursor[previous.field],
+          })),
+          {
+            [field]: {
+              [direction === 'asc' ? '$gt' : '$lt']: cursor[field],
+            },
+          },
+        ],
+      })),
+    };
+  }
+
+  private encodeCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const cursor: Record<string, any> = {
+      __sort: sort.map(({ field, direction }) => `${field}:${direction}`).join(','),
+    };
+    for (const { field } of sort) {
+      cursor[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
