    method: 'POST',
    expectedCode,
    app,
    jwt: jwt,
    entityManager,
    payload,
    query,
    crudConfig,
  });
  if (expectedCode !== 201) {
    return;
  }
  let resDb = (await entityManager
    .fork()
    .findOne(UserProfile, { id: res[crudConfig.id_field] })) as UserProfile;
